import okhttp3.OkHttpClient
import okhttp3.logging.HttpLoggingInterceptor
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory
import retrofit2.http.GET

const val DEV_BASE_URL = "https://dev.api.example.com/"
const val STAGING_BASE_URL = "https://staging.api.example.com/"
const val PROD_BASE_URL = "https://api.example.com/"

data class UserProfile(val username: String, val email: String)

interface UserService {
    @GET("users")
    suspend fun getUserProfiles(): List<UserProfile>
}

class NetworkModule(environment: String, authToken: String) {
    
    private val baseUrl = when(environment) {
        "dev" -> DEV_BASE_URL
        "staging" -> STAGING_BASE_URL
        else -> PROD_BASE_URL
    }

    private val client = OkHttpClient.Builder()
        .addInterceptor { chain ->
            val newRequest = chain.request().newBuilder()
            newRequest.addHeader("Authorization", "Bearer $authToken")
            chain.proceed(newRequest.build())
        }
        .addInterceptor(HttpLoggingInterceptor().apply {
            level = HttpLoggingInterceptor.Level.BODY
        })
        .build()

    val retrofit: Retrofit = Retrofit.Builder()
        .baseUrl(baseUrl)
        .client(client)
        .addConverterFactory(GsonConverterFactory.create())
        .build()

    val userService = retrofit.create(UserService::class.java)
}